import{_ as t,C as r,o as e,c as i,a5 as n,b as o,w as s,a as p,E as A,a4 as d}from"./chunks/framework.gGRxziV4.js";const B=JSON.parse('{"title":"渐进式披露","description":"","frontmatter":{},"headers":[],"relativePath":"05-Skill工程/02-渐进式披露.md","filePath":"05-Skill工程/02-渐进式披露.md","lastUpdated":1774181700000}'),E={name:"05-Skill工程/02-渐进式披露.md"};function c(h,a,u,b,g,m){const l=r("Mermaid");return e(),i("div",null,[a[1]||(a[1]=n('<h1 id="渐进式披露" tabindex="-1">渐进式披露 <a class="header-anchor" href="#渐进式披露" aria-label="Permalink to &quot;渐进式披露&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 5 模块的第 2 章。</p></blockquote><p>三层加载机制——近似无限上下文的秘密。不要一次性把所有能力暴露给模型，而是在需要的时候逐层展开。</p><hr><h2 id="为什么需要渐进式披露" tabindex="-1">为什么需要渐进式披露 <a class="header-anchor" href="#为什么需要渐进式披露" aria-label="Permalink to &quot;为什么需要渐进式披露&quot;">​</a></h2><p>如果把所有 Skill 的全文都塞进 System Prompt，会造成严重的上下文膨胀。100 个 Skill 每个 500 字就是 5 万字——Agent 还没开始干活，脑容量就被说明书占满一半。</p><p>而且当所有 Skill 都平铺在上下文中时，Agent 会眼花缭乱——更容易选择错误的 Skill，或者在不相关的 Skill 上浪费注意力。</p><hr><h2 id="三层加载机制" tabindex="-1">三层加载机制 <a class="header-anchor" href="#三层加载机制" aria-label="Permalink to &quot;三层加载机制&quot;">​</a></h2>',9)),(e(),o(d,null,{default:s(()=>[A(l,{id:"mermaid-25",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BAgent%20%E5%90%AF%E5%8A%A8%5D%20--%3E%20B%5B%E7%AC%AC%E4%B8%80%E5%B1%82%3A%20%E7%9B%AE%E5%BD%95%E5%B1%82%3Cbr%2F%3E%E5%A7%8B%E7%BB%88%E5%8A%A0%E8%BD%BD%20%E6%AF%8F%E4%B8%AASkill%E6%A0%87%E9%A2%98%2B%E6%8F%8F%E8%BF%B0%5D%0A%20%20%20%20B%20--%3E%20C%7BAgent%20%E6%B5%8F%E8%A7%88%E7%9B%AE%E5%BD%95%3Cbr%2F%3E%E5%86%B3%E5%AE%9A%E7%94%A8%E5%93%AA%E4%B8%AASkill%EF%BC%9F%7D%0A%20%20%20%20C%20--%3E%7C%E9%80%89%E4%B8%AD%20Skill%20X%7C%20D%5B%E7%AC%AC%E4%BA%8C%E5%B1%82%3A%20Skill%20%E5%85%A8%E6%96%87%3Cbr%2F%3Eread%20%E5%B7%A5%E5%85%B7%E6%8C%89%E9%9C%80%E5%8A%A0%E8%BD%BD%5D%0A%20%20%20%20D%20--%3E%20E%5BAgent%20%E6%8C%89%E6%AD%A5%E9%AA%A4%E6%89%A7%E8%A1%8C%5D%0A%20%20%20%20E%20--%3E%20F%7B%E9%9C%80%E8%A6%81%E6%89%A7%E8%A1%8C%E8%84%9A%E6%9C%AC%EF%BC%9F%7D%0A%20%20%20%20F%20--%3E%7C%E6%98%AF%7C%20G%5B%E7%AC%AC%E4%B8%89%E5%B1%82%3A%20%E8%84%9A%E6%9C%AC%E5%92%8C%E8%B5%84%E6%BA%90%3Cbr%2F%3E%E6%89%A7%E8%A1%8C%E6%97%B6%E6%89%8D%E5%8A%A0%E8%BD%BD%5D%0A%20%20%20%20F%20--%3E%7C%E5%90%A6%7C%20H%5B%E4%BB%BB%E5%8A%A1%E5%AE%8C%E6%88%90%5D%0A%20%20%20%20G%20--%3E%20H%0A%20%20%20%20D%20--%3E%20I%5B%E4%B8%8A%E4%B8%8B%E6%96%87%E5%8E%8B%E7%BC%A9%3Cbr%2F%3E%E5%8F%AF%E9%80%86%E7%A7%BB%E9%99%A4%5D%0A%20%20%20%20I%20--%3E%20B%0A%20%20%20%20style%20B%20fill%3A%234a9%0A%20%20%20%20style%20D%20fill%3A%238cf%0A%20%20%20%20style%20G%20fill%3A%23f96%0A"})]),fallback:s(()=>[...a[0]||(a[0]=[p(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=n(`<blockquote><p>💡 <strong>图解：</strong> 三层加载像洋葱剥皮——目录只占一行，全文按需才来，脚本执行时才出现——能力无限增长但上下文始终精简。</p></blockquote><h3 id="第一层-目录层-始终加载" tabindex="-1">第一层：目录层（始终加载） <a class="header-anchor" href="#第一层-目录层-始终加载" aria-label="Permalink to &quot;第一层：目录层（始终加载）&quot;">​</a></h3><p>每个 Skill 的标题和简短描述始终在上下文中。就像一本书的目录——你知道有哪些章节，但不知道每章的具体内容。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Available Skills:</span></span>
<span class="line"><span>- deploy-to-staging: 部署代码到预发布环境</span></span>
<span class="line"><span>- run-migration: 执行数据库迁移</span></span>
<span class="line"><span>- generate-changelog: 生成更新日志</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>这一层信息量极小，几乎不占用上下文空间。Agent 浏览目录，决定需要哪个 Skill。</p><h3 id="第二层-skill-全文-按需加载" tabindex="-1">第二层：Skill 全文（按需加载） <a class="header-anchor" href="#第二层-skill-全文-按需加载" aria-label="Permalink to &quot;第二层：Skill 全文（按需加载）&quot;">​</a></h3><p>当 Agent 决定使用某个 Skill 时，用 <code>read</code> 工具读取该 Skill 的完整 <code>.md</code> 文件。内容包括详细的操作步骤、注意事项、示例代码。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent 决策: &quot;我需要部署到预发布环境&quot;</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Agent 执行: read(&quot;skills/deploy-to-staging.md&quot;)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>加载完整内容到上下文</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>按步骤执行</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这一层只在需要时才加载，用完后可以通过上下文压缩移除。</p><h3 id="第三层-脚本和资源-执行时加载" tabindex="-1">第三层：脚本和资源（执行时加载） <a class="header-anchor" href="#第三层-脚本和资源-执行时加载" aria-label="Permalink to &quot;第三层：脚本和资源（执行时加载）&quot;">​</a></h3><p>Skill 中引用的脚本文件和资源模板，只在真正执行时才被加载。比如 deploy Skill 引用了一个 <code>deploy.sh</code> 脚本，Agent 读取 Skill 文档后知道需要执行这个脚本，但脚本内容不会进入上下文——而是直接被 bash 执行。</p><hr><h2 id="实现方式" tabindex="-1">实现方式 <a class="header-anchor" href="#实现方式" aria-label="Permalink to &quot;实现方式&quot;">​</a></h2><h3 id="anthropic-的做法" tabindex="-1">Anthropic 的做法 <a class="header-anchor" href="#anthropic-的做法" aria-label="Permalink to &quot;Anthropic 的做法&quot;">​</a></h3><p>Agent 启动时仅加载每个 Skill 的标题。当 Agent 决定使用某技能时，才用 <code>read</code> 工具完整读取。甚至连脚本也不必一开始就全部告知——Agent 通过 bash 工具在庞大脚本目录中自主寻找和阅读说明书。</p><h3 id="cursor-的做法" tabindex="-1">Cursor 的做法 <a class="header-anchor" href="#cursor-的做法" aria-label="Permalink to &quot;Cursor 的做法&quot;">​</a></h3><p>结合 Grep（关键词搜索）和语义搜索两种发现方式。能用关键词就用关键词——确定性强、速度快、结果可解释。关键词不够再用语义匹配——解决关键词不一致问题。</p><p>MCP 工具同样按需加载：工具说明书卸载到文件系统，初始 Prompt 只保留极简菜单（名称+描述）。Agent 需要时主动读取说明书文件。Token 消耗减少 46.9%。</p><h3 id="menlo-的做法" tabindex="-1">Menlo 的做法 <a class="header-anchor" href="#menlo-的做法" aria-label="Permalink to &quot;Menlo 的做法&quot;">​</a></h3><p>Agent 通过 <code>ls</code> 和 <code>--help</code> 在庞大脚本目录中自主寻找和学习。System Prompt 只提供关键的 API 文档索引，Agent 利用预训练编程知识组合积木块。</p><hr><h2 id="效果" tabindex="-1">效果 <a class="header-anchor" href="#效果" aria-label="Permalink to &quot;效果&quot;">​</a></h2><p><strong>Token 效率</strong>：Agent 的能力在不断增长，但工具列表并没有膨胀。上下文始终保持精简。</p><p><strong>认知聚焦</strong>：Agent 不会在不相关的 Skill 上分心，注意力集中在当前任务需要的能力上。</p><p><strong>可扩展性</strong>：新增 Skill 只需要在目录层增加一行描述，不需要修改核心 Prompt。系统功能可以无限扩展，但接口复杂度保持不变。</p><p><strong>用户体验</strong>：当工具不可用时（比如 GitHub 账号掉线），Agent 不会说&quot;我不会&quot;，而是说&quot;我有这个能力但现在需要重新登录&quot;——从程序变成专业的合作伙伴。</p><hr><h2 id="设计原则" tabindex="-1">设计原则 <a class="header-anchor" href="#设计原则" aria-label="Permalink to &quot;设计原则&quot;">​</a></h2><p><strong>渐进而非突变</strong>：信息应该像水一样自然流动——从目录到全文到执行，每一层都只加载当下需要的内容。</p><p><strong>目录即承诺</strong>：目录层是 Agent 的导航地图。目录描述不准确会导致 Agent 选择错误的 Skill。</p><p><strong>可逆的加载</strong>：加载的内容应该可以被压缩或移除，不会永久增加上下文负担。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>三层加载：目录层（始终加载）→ Skill 全文（按需）→ 脚本资源（执行时）</li><li>发现方式：Grep 关键词 + 语义搜索</li><li>效果：能力增长但工具列表不膨胀，Token 效率提升 46.9%</li><li>设计原则：渐进、目录即承诺、可逆加载</li></ul><hr><p><strong>上一章</strong>: <a href="./01-Skill是什么.html">Skill是什么</a> | <strong>下一章</strong>: <a href="./03-开发与安全.html">开发、评估与安全</a></p>`,36))])}const C=t(E,[["render",c]]);export{B as __pageData,C as default};
